ALTER TABLE "DIRKSPZM32"."DIS_CFG" ADD CONSTRAINT "CHECK_DIS_CFG_CONNECTOR_TYPE" CHECK (Connector_type in ('CON_IPS_FILE', 'CON_IPS_SAPRFC', 'CON_IPS_PCS')) ENABLE;
