ALTER TABLE "DIRKSPZM32"."DIS_CFG" ADD CONSTRAINT "PK_DIS_CFG" PRIMARY KEY ("SID", "FIRMA_NR", "CONNECTOR_NAME")
  USING INDEX  ENABLE;


